var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"제6 방위선 함락 후, 72시간 경과","JPN":"第6防衛線陥落後、72時間経過","ENG":"72 hours after the fall of the 6th Defense Line","TWN":"第六防線淪陷後經過72小時","THA":"72 ชั่วโมงหลังจากการล่มสลายของแนวป้องกันที่ 6","VTN":"72 giờ sau khi Phòng Tuyến thứ 6 thất thủ","SCN":"第6防线沦陷，72小时后","DEU":"72 Stunden nach dem Fall der 6. Verteidigungslinie","FRA":"72 heures après la chute de la 6e ligne de défense"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제5 방위선\\n<color=#ffd34c>아포리아 공략 작전 수행 중</color>","JPN":"人類統合防衛軍第5防衛線\\n<color=#ffd34c>アポリア攻略作戦遂行中</color>","ENG":"[[","TWN":"人類共同保衛軍第五防線\\n<color=#ffd34c>執行攻陷阿波利亞作戰中</color>","THA":"แนวป้องกันที่ 5 กองกำลังป้องกันมนุษยชาติ\\n<color=#ffd34c>ปฏิบัติการอาโพเรียอยู่ระหว่างดำเนินการ</color>","VTN":"Phòng Tuyến thứ 5 của Lực Lượng Phòng Vệ Nhân Loại Thống Nhất\\n<color=#ffd34c>Chiến dịch Aporia đang được tiến hành</color>","SCN":"人类综合防卫军第5防线\\n<color=#ffd34c>阿波利亚作战执行中</color>","DEU":"5. Verteidigungslinie der Verteidigungsstreitkräfte der vereinigten Menschheit\\n<color=#ffd34c>Operation „Aporia“ läuft</color>","FRA":"5e ligne de défense des Forces de défense unies de l'humanité\\n<color=#ffd34c>Opération Aporia en cours</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음, 그런데 박사님.","JPN":"ふむ……ところで博士。","ENG":"Hmm, but Doc.","TWN":"唔，博士。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"정말로 아포리아가 우리 생각대로 여길 공격하러 올까요?","JPN":"本当にアポリアが私たちの予想通り、ここを攻めてきますかね？","ENG":"Do you really believe Aporia will come and attack this area, like we imagined?","TWN":"阿波利亞真的會像我們預想的一樣攻擊這裡嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"여기가 아니라, 다른 곳에 갔으면 우리 작전은 실패하는 거잖아요.","JPN":"ここじゃないどこかに行かれてしまったら、私たちの作戦は失敗じゃないですか。","ENG":"If it went somewhere else, then our operation would be a bust.","TWN":"萬一他不來這裡，而是去其他地方的話，那我們的作戰可就失敗了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"재수없는 소리 하지 마.","JPN":"縁起の悪いこと言うなよ。","ENG":"Don't jinx it.","TWN":"少烏鴉嘴。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"녀석이 이끄는 침식체 무리는 항상 고치를 관리하는 관측소를 가장 먼저 습격했지.","JPN":"奴が率いる侵食体の群れは、毎回繭を管理する観測所から先に襲撃している。","ENG":"The C.O. horde it leads always attacked the cocoon observatory first.","TWN":"那傢伙帶領的侵蝕體群，總是最先攻擊保管繭的觀測站。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아마도 고치를 흡수할 때, 최대한 방해받지 않기 위해서일 거야.","JPN":"おそらく繭を吸収するときに、できるだけ邪魔が入らないようにするためだろうな。","ENG":"I think it's so it doesn't get disturbed while it absorbs the cocoon.","TWN":"也許是為了吸收繭的時候，盡量不受打擾。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그러니까 이번에도 이곳 관측소부터 노려올 가능성이 커.","JPN":"だから今回も、この観測所を狙ってくる可能性は高い。","ENG":"So, it's highly likely that Aporia will come to this observatory.","TWN":"所以，這次襲擊這個觀測站的可能性很高。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음, 하지만 괜찮을까요, 카린 양?","JPN":"ふむ……でも大丈夫なんですかね、カリンさん？","ENG":"Hmm, but are you sure this will be okay, Karin?","TWN":"嗯，但是作戰能成功嗎，卡琳？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아포리아가 여길 노린다고 해도, 그 침식체에게는 통상 병기가 통하지 않잖아요.","JPN":"アポリアがここを攻めてきたとしても、あの侵食体に通常の兵器は効かないですよ。","ENG":"Even if Aporia comes here, none of our normal weapons can do any damage to him.","TWN":"就算阿波利亞襲擊了這裡，普通的兵器可對付不了那個侵蝕體。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"물론, 일반적인 병기라면 데미지를 주기 힘들겠죠.","JPN":"もちろん、一般的な兵器であれば、ダメージを与えるのは難しいでしょうね。","ENG":"Yes, it will be difficult to harm him with ordinary weapons.","TWN":"沒錯，如果是普通的兵器無法對他造成傷害。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이번에 사용할 <color=#ffd34c>이터니움 반응 탄두 미사일</color>, 서른두 발은…….","JPN":"今回使用する<color=#ffd34c>エタニウム反応弾道ミサイル</color>、32発は……","ENG":"But the 32 shots of <color=#ffd34c>Eternium-reactive warhead missiles</color> we'll be using this time...","TWN":"這次對付他要用的是<color=#ffd34c>永恆之金反應導彈</color>，32枚……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"원래라면 각각 연구중인 시험용 함선의 엔진을 개조해서 만든 미사일이에요.","JPN":"本来であれば、各々が研究中の実験用艦船のエンジンとなるはずでした。ミサイルはそれを改造したもの。","ENG":"The missiles were manufactured using modified engines from test ships that were originally built for research purposes.","TWN":"每個都是由研究中試驗艦船的引擎改造而成。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"미래를 소모시킨 미사일 서른 두발이 지금 인류가 가용할 수 있는 최대 화력이고요.","JPN":"つまり、未来を削って生み出したミサイル32発が、現在の人類に使用できる最大の火力なんです。","ENG":"Right now, humanity's only weapons are the 32 missiles created by sacrificing the future.","TWN":"這32枚導彈是我們目前可使用的最強火力，預支的是人類的未來。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그 말은, 이 작전이 실패하면 다시는 그 이상의 화력을 기대할 수 없다는 이야기네요?","JPN":"ってことは、この作戦が失敗したら二度とそれ以上の火力は期待できないということですよね？","ENG":"So you're saying that if this operation fails, we can never expect any more firepower?","TWN":"你的意思是，如果這次作戰失敗的話，就不會有更強的火力了？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};